+        return doTransaction('sites', 'readwrite', store => store.delete(id));
+    },
+
+    // Inspections
+    saveInspection: function (inspection) {
+        return doTransaction('inspections', 'readwrite', store => store.put(inspection));
+    },
+    getAllInspections: function () {
+        return doTransaction('inspections', 'readonly', store => store.getAll());
+    },
+    getInspection: function (id) {
+        return doTransaction('inspections', 'readonly', store => store.get(id));
+    },
+    getInspectionsBySite: function (siteId) {
+        return openDb().then(database => {
+            return new Promise((resolve, reject) => {
+                const tx = database.transaction('inspections', 'readonly');
+                const store = tx.objectStore('inspections');
+                const index = store.index('siteId');
+                const request = index.getAll(siteId);
+                request.onsuccess = () => resolve(request.result);
+                request.onerror = (e) => reject(e.target.error);
+            });
+        });
+    },
+    deleteInspection: function (id) {
+        return doTransaction('inspections', 'readwrite', store => store.delete(id));
+    },
+    getPendingInspections: function () {
+        return openDb().then(database => {
+            return new Promise((resolve, reject) => {
+                const tx = database.transaction('inspections', 'readonly');
+                const store = tx.objectStore('inspections');
+                const request = store.getAll();
+                request.onsuccess = () => {
+                    const pending = request.result.filter(i => i.status === 0);
+                    resolve(pending);
+                };
+                request.onerror = (e) => reject(e.target.error);
+            });
+        });
+    },
+    markInspectionSynced: function (id) {
+        return openDb().then(database => {
+            return new Promise((resolve, reject) => {
+                const tx = database.transaction('inspections', 'readwrite');
+                const store = tx.objectStore('inspections');
+                const getReq = store.get(id);
+                getReq.onsuccess = () => {
+                    const inspection = getReq.result;
+                    if (inspection) {
+                        inspection.status = 1; // Synced
+                        const putReq = store.put(inspection);
+                        putReq.onsuccess = () => resolve(true);
+                        putReq.onerror = (e) => reject(e.target.error);
+                    } else {
+                        resolve(false);
+                    }
+                };
+                getReq.onerror = (e) => reject(e.target.error);
+            });
+        });
+    },
+
+    // Photos
+    savePhoto: function (photo) {
+        return doTransaction('photos', 'readwrite', store => store.put(photo));
+    },
+    getPhotosByInspection: function (inspectionId) {
+        return openDb().then(database => {
+            return new Promise((resolve, reject) => {
+                const tx = database.transaction('photos', 'readonly');
+                const store = tx.objectStore('photos');
+                const index = store.index('inspectionId');
+                const request = index.getAll(inspectionId);
+                request.onsuccess = () => resolve(request.result);
+                request.onerror = (e) => reject(e.target.error);
+            });
+        });
+    },
+    deletePhoto: function (id) {
+        return doTransaction('photos', 'readwrite', store => store.delete(id));
+    }
+};
+
+// Connectivity helpers
+window.connectivityFunctions = {
+    isOnline: function () {
+        return navigator.onLine;
+    },
+    registerOnlineHandler: function (dotNetRef) {
+        window.addEventListener('online', () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', true));
+        window.addEventListener('offline', () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', false));
+    }
+};
+
+// Photo resize helper
+window.photoFunctions = {
+    resizeImage: function (base64, maxWidth, maxHeight) {
+        return new Promise((resolve) => {
+            const img = new Image();
+            img.onload = () => {
+                let width = img.width;
+                let height = img.height;
+                if (width > maxWidth || height > maxHeight) {
+                    const ratio = Math.min(maxWidth / width, maxHeight / height);
+                    width = Math.floor(width * ratio);
+                    height = Math.floor(height * ratio);
+                }
+                const canvas = document.createElement('canvas');
+                canvas.width = width;
+                canvas.height = height;
+                const ctx = canvas.getContext('2d');
+                ctx.drawImage(img, 0, 0, width, height);
+                resolve(canvas.toDataURL('image/jpeg', 0.7));
+            };
+            img.src = base64;
+        });
+    }
+};
+

