+using System.Net.Http.Json;
+using SiteInspector.Client.Models;
+
+namespace SiteInspector.Client.Services;
+
+public class SyncService : ISyncService
+{
+    private readonly HttpClient _http;
+    private readonly IOfflineStorageService _storage;
+
+    public SyncService(HttpClient http, IOfflineStorageService storage)
+    {
+        _http = http;
+        _storage = storage;
+    }
+
+    public async Task SyncPendingInspectionsAsync()
+    {
+        try
+        {
+            var pending = await _storage.GetPendingInspectionsAsync();
+            foreach (var inspection in pending)
+            {
+                var photos = await _storage.GetPhotosByInspectionAsync(inspection.Id);
+                inspection.Photos = photos;
+
+                var response = await _http.PostAsJsonAsync("/api/sync/inspections", inspection);
+                if (response.IsSuccessStatusCode)
+                {
+                    await _storage.MarkInspectionSyncedAsync(inspection.Id);
+                }
+            }
+        }
+        catch
+        {
+            // Sync failed silently — will retry next time connectivity returns
+        }
+    }
+}
+

