+using Microsoft.JSInterop;
+
+namespace SiteInspector.Client.Services;
+
+public class ConnectivityService : IAsyncDisposable
+{
+    private readonly IJSRuntime _js;
+    private readonly ISyncService _syncService;
+    private DotNetObjectReference<ConnectivityService>? _dotNetRef;
+
+    public bool IsOnline { get; private set; } = true;
+    public event Action<bool>? ConnectivityChanged;
+
+    public ConnectivityService(IJSRuntime js, ISyncService syncService)
+    {
+        _js = js;
+        _syncService = syncService;
+    }
+
+    public async Task InitializeAsync()
+    {
+        _dotNetRef = DotNetObjectReference.Create(this);
+        IsOnline = await _js.InvokeAsync<bool>("connectivityFunctions.isOnline");
+        await _js.InvokeVoidAsync("connectivityFunctions.registerOnlineHandler", _dotNetRef);
+    }
+
+    [JSInvokable]
+    public async Task OnConnectivityChanged(bool isOnline)
+    {
+        IsOnline = isOnline;
+        ConnectivityChanged?.Invoke(isOnline);
+
+        if (isOnline)
+        {
+            await _syncService.SyncPendingInspectionsAsync();
+        }
+    }
+
+    public async ValueTask DisposeAsync()
+    {
+        _dotNetRef?.Dispose();
+    }
+}
+

