@page "/"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject IOfflineStorageService Storage
@inject NavigationManager Navigation

<div class="page-header">
    <h1>🏗️ Sites</h1>
</div>

@if (_showAddForm)
{
    <div class="card form-card">
        <div class="card-body">
            <h3>Add New Site</h3>
            <div class="form-group">
                <label>Site Name</label>
                <input type="text" class="form-control" @bind="_newSite.Name" placeholder="e.g. Riverside Apartments" />
            </div>
            <div class="form-group">
                <label>Address</label>
                <input type="text" class="form-control" @bind="_newSite.Address" placeholder="e.g. 123 Main St" />
            </div>
            <div class="form-actions">
                <button class="btn btn-primary btn-lg" @onclick="SaveSite">Save Site</button>
                <button class="btn btn-secondary btn-lg" @onclick="() => _showAddForm = false">Cancel</button>
            </div>
        </div>
    </div>
}
else
{
    <button class="btn btn-primary btn-lg btn-block" @onclick="() => _showAddForm = true">
        ➕ Add New Site
    </button>
}

@if (_sites == null)
{
    <div class="loading">Loading sites...</div>
}
else if (_sites.Count == 0)
{
    <div class="empty-state">
        <p>No sites yet. Add your first construction site to get started.</p>
    </div>
}
else
{
    <div class="site-list">
        @foreach (var site in _sites)
        {
            <div class="card site-card" @onclick="() => NavigateToSite(site.Id)">
                <div class="card-body">
                    <h3>@site.Name</h3>
                    <p class="site-address">📍 @site.Address</p>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<Site>? _sites;
    private bool _showAddForm;
    private Site _newSite = new();

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        _sites = await Storage.GetAllSitesAsync();
    }

    private async Task SaveSite()
    {
        if (string.IsNullOrWhiteSpace(_newSite.Name)) return;

        await Storage.SaveSiteAsync(_newSite);
        _sites = await Storage.GetAllSitesAsync();
        _newSite = new();
        _showAddForm = false;
    }

    private void NavigateToSite(string siteId)
    {
        Navigation.NavigateTo($"/site/{siteId}");
    }
}

@page "/site/{SiteId}"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject IOfflineStorageService Storage
@inject NavigationManager Navigation

<div class="page-header">
    <button class="btn-back" @onclick="() => Navigation.NavigateTo("/")">← Back</button>
    <h1>@(_site?.Name ?? "Loading...")</h1>
    @if (_site != null)
    {
        <p class="site-address">📍 @_site.Address</p>
    }
</div>

<button class="btn btn-primary btn-lg btn-block" @onclick="StartNewInspection">
    📋 Start New Inspection
</button>

@if (_inspections == null)
{
    <div class="loading">Loading inspections...</div>
}
else if (_inspections.Count == 0)
{
    <div class="empty-state">
        <p>No inspections yet for this site.</p>
    </div>
}
else
{
    <div class="inspection-list">
        @foreach (var inspection in _inspections.OrderByDescending(i => i.Date))
        {
            <div class="card inspection-card" @onclick="() => ViewInspection(inspection.Id)">
                <div class="card-body">
                    <div class="inspection-header">
                        <span class="inspection-date">📅 @inspection.Date.ToString("dd MMM yyyy HH:mm")</span>
                        <span class="sync-badge @GetSyncClass(inspection.Status)">@inspection.Status</span>
                    </div>
                    <p class="inspection-summary">
                        ✅ @inspection.ChecklistItems.Count(c => c.IsChecked) / @inspection.ChecklistItems.Count items checked
                    </p>
                    @if (!string.IsNullOrEmpty(inspection.Notes))
                    {
                        <p class="inspection-notes">@inspection.Notes</p>
                    }
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private Site? _site;
    private List<Inspection>? _inspections;

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        _site = await Storage.GetSiteAsync(SiteId);
        _inspections = await Storage.GetInspectionsBySiteAsync(SiteId);
    }

    private void StartNewInspection()
    {
        Navigation.NavigateTo($"/inspection/new/{SiteId}");
    }

    private void ViewInspection(string id)
    {
        Navigation.NavigateTo($"/inspection/{id}");
    }

    private string GetSyncClass(SyncStatus status) => status switch
    {
        SyncStatus.Pending => "badge-pending",
        SyncStatus.Synced => "badge-synced",
        SyncStatus.Failed => "badge-failed",
        _ => ""
    };
}

@page "/inspection/new/{SiteId}"
@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject IOfflineStorageService Storage
@inject NavigationManager Navigation
@inject IJSRuntime JS

<div class="page-header">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h1>New Inspection</h1>
</div>

<div class="checklist-container">
    @foreach (var category in _inspection.ChecklistItems.GroupBy(c => c.Category))
    {
        <div class="category-section">
            <h3 class="category-title">@category.Key</h3>
            @foreach (var item in category)
            {
                <div class="checklist-item @(item.IsChecked ? "checked" : "")" @onclick="() => ToggleItem(item)">
                    <div class="check-indicator">
                        @if (item.IsChecked)
                        {
                            <span class="check-mark">✅</span>
                        }
                        else
                        {
                            <span class="check-mark">⬜</span>
                        }
                    </div>
                    <div class="item-content">
                        <span class="item-description">@item.Description</span>
                        <input type="text" class="item-notes" placeholder="Add note..."
                               @bind="item.Notes" @onclick:stopPropagation="true" />
                    </div>
                </div>
            }
        </div>
    }

    <div class="category-section">
        <h3 class="category-title">📝 General Notes</h3>
        <textarea class="form-control notes-textarea" rows="4"
                  placeholder="Additional observations..."
                  @bind="_inspection.Notes"></textarea>
    </div>

    <div class="category-section">
        <h3 class="category-title">📷 Photos</h3>
        <label class="btn btn-secondary btn-lg btn-block photo-btn">
            📸 Take Photo
            <InputFile accept="image/*" capture="environment" OnChange="OnPhotoSelected" style="display:none" />
        </label>

        @if (_photos.Count > 0)
        {
            <div class="photo-grid">
                @foreach (var photo in _photos)
                {
                    <div class="photo-thumbnail">
                        <img src="@photo.Base64Data" alt="@photo.FileName" />
                        <button class="photo-remove" @onclick="() => RemovePhoto(photo)">✕</button>
                    </div>
                }
            </div>
        }
    </div>

    <div class="form-actions sticky-bottom">
        <button class="btn btn-success btn-lg btn-block" @onclick="SaveInspection" disabled="@_saving">
            @if (_saving)
            {
                <span>Saving...</span>
            }
            else
            {
                <span>💾 Save Inspection</span>
            }
        </button>
    </div>
</div>

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private Inspection _inspection = new();
    private List<InspectionPhoto> _photos = new();
    private bool _saving;

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        _inspection.SiteId = SiteId;
        _inspection.ChecklistItems = ChecklistTemplates.GetDefaultChecklist();
    }

    private void ToggleItem(ChecklistItem item)
    {
        item.IsChecked = !item.IsChecked;
    }

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(5))
        {
            try
            {
                var buffer = new byte[file.Size];
                await file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024).ReadAsync(buffer);
                var base64 = $"data:{file.ContentType};base64,{Convert.ToBase64String(buffer)}";

                // Resize on client
                var resized = await JS.InvokeAsync<string>("photoFunctions.resizeImage", base64, 1024, 1024);

                var photo = new InspectionPhoto
                {
                    InspectionId = _inspection.Id,
                    FileName = file.Name,
                    Base64Data = resized,
                    CapturedAt = DateTime.UtcNow
                };
                _photos.Add(photo);
            }
            catch
            {
                // Skip files that fail to process
            }
        }
    }

    private void RemovePhoto(InspectionPhoto photo)
    {
        _photos.Remove(photo);
    }

    private async Task SaveInspection()
    {
        _saving = true;
        try
        {
            _inspection.Date = DateTime.UtcNow;
            _inspection.Status = SyncStatus.Pending;
            await Storage.SaveInspectionAsync(_inspection);

            foreach (var photo in _photos)
            {
                await Storage.SavePhotoAsync(photo);
            }

            Navigation.NavigateTo($"/site/{SiteId}");
        }
        finally
        {
            _saving = false;
        }
    }

    private void GoBack()
    {
        Navigation.NavigateTo($"/site/{SiteId}");
    }
}

