+@using SiteInspector.Client.Models
+@using SiteInspector.Client.Services
+@inject IOfflineStorageService Storage
+@inject NavigationManager Navigation
+
+<div class="page-header">
+    <button class="btn-back" @onclick="GoBack">← Back</button>
+    <h1>Inspection Details</h1>
+    @if (_inspection != null)
+    {
+        <p class="inspection-meta">📅 @_inspection.Date.ToString("dd MMM yyyy HH:mm")
+            <span class="sync-badge @GetSyncClass(_inspection.Status)">@_inspection.Status</span>
+        </p>
+    }
+</div>
+
+@if (_inspection == null)
+{
+    <div class="loading">Loading...</div>
+}
+else
+{
+    <div class="checklist-container">
+        @foreach (var category in _inspection.ChecklistItems.GroupBy(c => c.Category))
+        {
+            <div class="category-section">
+                <h3 class="category-title">@category.Key</h3>
+                @foreach (var item in category)
+                {
+                    <div class="checklist-item @(item.IsChecked ? "checked" : "unchecked") readonly">
+                        <div class="check-indicator">
+                            <span class="check-mark">@(item.IsChecked ? "✅" : "❌")</span>
+                        </div>
+                        <div class="item-content">
+                            <span class="item-description">@item.Description</span>
+                            @if (!string.IsNullOrEmpty(item.Notes))
+                            {
+                                <span class="item-note-display">📝 @item.Notes</span>
+                            }
+                        </div>
+                    </div>
+                }
+            </div>
+        }
+
+        @if (!string.IsNullOrEmpty(_inspection.Notes))
+        {
+            <div class="category-section">
+                <h3 class="category-title">📝 General Notes</h3>
+                <p class="general-notes">@_inspection.Notes</p>
+            </div>
+        }
+
+        @if (_photos.Count > 0)
+        {
+            <div class="category-section">
+                <h3 class="category-title">📷 Photos (@_photos.Count)</h3>
+                <div class="photo-grid">
+                    @foreach (var photo in _photos)
+                    {
+                        <div class="photo-thumbnail large">
+                            <img src="@photo.Base64Data" alt="@photo.FileName" />
+                            <span class="photo-time">@photo.CapturedAt.ToString("HH:mm")</span>
+                        </div>
+                    }
+                </div>
+            </div>
+        }
+
+        <div class="inspection-summary-bar">
+            <span>✅ @_inspection.ChecklistItems.Count(c => c.IsChecked) passed</span>
+            <span>❌ @_inspection.ChecklistItems.Count(c => !c.IsChecked) failed</span>
+            <span>📷 @_photos.Count photos</span>
+        </div>
+    </div>
+}
+
+@code {
+    [Parameter] public string InspectionId { get; set; } = string.Empty;
+
+    private Inspection? _inspection;
+    private List<InspectionPhoto> _photos = new();
+
+    protected override async Task OnInitializedAsync()
+    {
+        await Storage.InitializeAsync();
+        _inspection = await Storage.GetInspectionAsync(InspectionId);
+        if (_inspection != null)
+        {
+            _photos = await Storage.GetPhotosByInspectionAsync(InspectionId);
+        }
+    }
+
+    private void GoBack()
+    {
+        if (_inspection != null)
+        {
+            Navigation.NavigateTo($"/site/{_inspection.SiteId}");
+        }
+        else
+        {
+            Navigation.NavigateTo("/");
+        }
+    }
+
+    private string GetSyncClass(SyncStatus status) => status switch
+    {
+        SyncStatus.Pending => "badge-pending",
+        SyncStatus.Synced => "badge-synced",
+        SyncStatus.Failed => "badge-failed",
+        _ => ""
+    };
+}
+

