/* Site Inspector - Mobile-first CSS */
:root {
    --primary: #1a237e;
    --primary-light: #534bae;
    --accent: #ff6f00;
    --success: #2e7d32;
    --danger: #c62828;
    --warning: #f9a825;
    --bg: #f5f5f5;
    --card-bg: #ffffff;
    --text: #212121;
    --text-secondary: #757575;
    --border: #e0e0e0;
    --shadow: 0 2px 8px rgba(0,0,0,0.1);
    --radius: 12px;
    --touch-target: 48px;
}

* {
    box-sizing: border-box;
    -webkit-tap-highlight-color: transparent;
}

html, body {
    margin: 0;
    padding: 0;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    background: var(--bg);
    color: var(--text);
    font-size: 16px;
    line-height: 1.5;
    -webkit-font-smoothing: antialiased;
    overflow-x: hidden;
}

/* App Shell */
.app-shell {
    display: flex;
    flex-direction: column;
    min-height: 100dvh;
}

.app-header {
    position: sticky;
    top: 0;
    z-index: 100;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    background: var(--primary);
    color: white;
    box-shadow: var(--shadow);
}

.app-title {
    font-size: 1.2rem;
    font-weight: 700;
}

.connectivity-badge {
    font-size: 0.75rem;
    padding: 4px 10px;
    border-radius: 20px;
    font-weight: 600;
}

.connectivity-badge.online {
    background: var(--success);
    color: white;
}

.connectivity-badge.offline {
    background: var(--warning);
    color: #333;
}

.app-content {
    flex: 1;
    padding: 16px;
    padding-bottom: 80px;
    max-width: 600px;
    margin: 0 auto;
    width: 100%;
}

/* Bottom Navigation */
.bottom-nav {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    background: white;
    border-top: 1px solid var(--border);
    box-shadow: 0 -2px 8px rgba(0,0,0,0.1);
    z-index: 100;
    padding: 8px 0;
    padding-bottom: env(safe-area-inset-bottom, 8px);
}

.nav-items {
    display: flex;
    justify-content: center;
    align-items: center;
}

.nav-items .nav-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 8px 24px;
    text-decoration: none;
    color: var(--text-secondary);
    min-height: var(--touch-target);
    justify-content: center;
}

.nav-items .nav-item.active {
    color: var(--primary);
}

.nav-icon {
    font-size: 1.4rem;
}

.nav-label {
    font-size: 0.7rem;
    margin-top: 2px;
}

/* Page Headers */
.page-header {
    margin-bottom: 16px;
}

.page-header h1 {
    font-size: 1.5rem;
    font-weight: 700;
    margin: 0 0 4px 0;
}

/* Buttons */
.btn {
    border: none;
    border-radius: var(--radius);
    font-weight: 600;
    cursor: pointer;
    transition: transform 0.1s, opacity 0.1s;
    text-align: center;
    text-decoration: none;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
}

.btn:active {
    transform: scale(0.97);
    opacity: 0.9;
}

.btn-lg {
    min-height: var(--touch-target);
    padding: 12px 24px;
    font-size: 1rem;
}

.btn-block {
    display: flex;
    width: 100%;
}

.btn-primary {
    background: var(--primary);
    color: white;
}

.btn-secondary {
    background: var(--border);
    color: var(--text);
}

.btn-success {
    background: var(--success);
    color: white;
}

.btn-back {
    background: none;
    border: none;
    color: var(--primary);
    font-size: 1rem;
    font-weight: 600;
    padding: 8px 0;
    cursor: pointer;
    min-height: var(--touch-target);
    display: flex;
    align-items: center;
}

/* Cards */
.card {
    background: var(--card-bg);
    border-radius: var(--radius);
    box-shadow: var(--shadow);
    margin-bottom: 12px;
    border: none;
    overflow: hidden;
    transition: transform 0.1s;
}

.card:active {
    transform: scale(0.98);
}

.card-body {
    padding: 16px;
}

.site-card, .inspection-card {
    cursor: pointer;
}

.site-card h3 {
    font-size: 1.1rem;
    margin: 0 0 4px 0;
}

.site-address {
    color: var(--text-secondary);
    margin: 0;
    font-size: 0.9rem;
}

/* Forms */
.form-card {
    cursor: default;
}

.form-card:active {
    transform: none;
}

.form-group {
    margin-bottom: 16px;
}

.form-group label {
    display: block;
    font-weight: 600;
    margin-bottom: 6px;
    font-size: 0.9rem;
}

.form-control {
    width: 100%;
    padding: 12px 16px;
    border: 2px solid var(--border);
    border-radius: 8px;
    font-size: 1rem;
    min-height: var(--touch-target);
    transition: border-color 0.2s;
}

.form-control:focus {
    outline: none;
    border-color: var(--primary);
}

.form-actions {
    display: flex;
    gap: 12px;
    margin-top: 16px;
}

/* Checklist */
.checklist-container {
    padding-bottom: 80px;
}

.category-section {
    margin-bottom: 24px;
}

.category-title {
    font-size: 1rem;
    font-weight: 700;
    color: var(--primary);
    margin: 0 0 12px 0;
    padding: 8px 0;
    border-bottom: 2px solid var(--primary);
}

.checklist-item {
    display: flex;
    align-items: flex-start;
    gap: 12px;
    padding: 12px;
    background: var(--card-bg);
    border-radius: 8px;
    margin-bottom: 8px;
    cursor: pointer;
    min-height: var(--touch-target);
    border: 2px solid var(--border);
    transition: border-color 0.2s, background 0.2s;
}

.checklist-item.checked {
    border-color: var(--success);
    background: #e8f5e9;
}

.checklist-item.readonly {
    cursor: default;
}

.checklist-item.unchecked {
    border-color: var(--danger);
    background: #ffebee;
}

.check-indicator {
    font-size: 1.4rem;
    min-width: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.item-content {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 6px;
}

.item-description {
    font-size: 0.95rem;
    font-weight: 500;
}

.item-notes {
    width: 100%;
    padding: 8px 12px;
    border: 1px solid var(--border);
    border-radius: 6px;
    font-size: 0.85rem;
    min-height: 36px;
}

.item-note-display {
    font-size: 0.85rem;
    color: var(--text-secondary);
    font-style: italic;
}

.notes-textarea {
    resize: vertical;
    min-height: 100px;
}

/* Photos */
.photo-btn {
    margin-bottom: 12px;
}

.photo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
    gap: 8px;
    margin-top: 12px;
}

.photo-thumbnail {
    position: relative;
    aspect-ratio: 1;
    border-radius: 8px;
    overflow: hidden;
}

.photo-thumbnail.large {
    aspect-ratio: 4/3;
    grid-column: span 2;
}

.photo-thumbnail img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.photo-remove {
    position: absolute;
    top: 4px;
    right: 4px;
    width: 28px;
    height: 28px;
    border-radius: 50%;
    background: var(--danger);
    color: white;
    border: none;
    font-size: 0.9rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
}

.photo-time {
    position: absolute;
    bottom: 4px;
    left: 4px;
    background: rgba(0,0,0,0.6);
    color: white;
    font-size: 0.7rem;
    padding: 2px 6px;
    border-radius: 4px;
}

/* Sync badges */
.sync-badge {
    display: inline-block;
    font-size: 0.7rem;
    padding: 2px 8px;
    border-radius: 12px;
    font-weight: 600;
    text-transform: uppercase;
}

.badge-pending {
    background: var(--warning);
    color: #333;
}

.badge-synced {
    background: var(--success);
    color: white;
}

.badge-failed {
