+    display: flex;
+    align-items: center;
+}
+
+/* Cards */
+.card {
+    background: var(--card-bg);
+    border-radius: var(--radius);
+    box-shadow: var(--shadow);
+    margin-bottom: 12px;
+    border: none;
+    overflow: hidden;
+    transition: transform 0.1s;
+}
+
+.card:active {
+    transform: scale(0.98);
+}
+
+.card-body {
+    padding: 16px;
+}
+
+.site-card, .inspection-card {
+    cursor: pointer;
+}
+
+.site-card h3 {
+    font-size: 1.1rem;
+    margin: 0 0 4px 0;
+}
+
+.site-address {
+    color: var(--text-secondary);
+    margin: 0;
+    font-size: 0.9rem;
+}
+
+/* Forms */
+.form-card {
+    cursor: default;
+}
+
+.form-card:active {
+    transform: none;
+}
+
+.form-group {
+    margin-bottom: 16px;
+}
+
+.form-group label {
+    display: block;
+    font-weight: 600;
+    margin-bottom: 6px;
+    font-size: 0.9rem;
+}
+
+.form-control {
+    width: 100%;
+    padding: 12px 16px;
+    border: 2px solid var(--border);
+    border-radius: 8px;
+    font-size: 1rem;
+    min-height: var(--touch-target);
+    transition: border-color 0.2s;
+}
+
+.form-control:focus {
+    outline: none;
+    border-color: var(--primary);
+}
+
+.form-actions {
+    display: flex;
+    gap: 12px;
+    margin-top: 16px;
+}
+
+/* Checklist */
+.checklist-container {
+    padding-bottom: 80px;
+}
+
+.category-section {
+    margin-bottom: 24px;
+}
+
+.category-title {
+    font-size: 1rem;
+    font-weight: 700;
+    color: var(--primary);
+    margin: 0 0 12px 0;
+    padding: 8px 0;
+    border-bottom: 2px solid var(--primary);
+}
+
+.checklist-item {
+    display: flex;
+    align-items: flex-start;
+    gap: 12px;
+    padding: 12px;
+    background: var(--card-bg);
+    border-radius: 8px;
+    margin-bottom: 8px;
+    cursor: pointer;
+    min-height: var(--touch-target);
+    border: 2px solid var(--border);
+    transition: border-color 0.2s, background 0.2s;
+}
+
+.checklist-item.checked {
+    border-color: var(--success);
+    background: #e8f5e9;
+}
+
+.checklist-item.readonly {
+    cursor: default;
+}
+
+.checklist-item.unchecked {
+    border-color: var(--danger);
+    background: #ffebee;
+}
+
+.check-indicator {
+    font-size: 1.4rem;
+    min-width: 32px;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+}
+
+.item-content {
+    flex: 1;
+    display: flex;
+    flex-direction: column;
+    gap: 6px;
+}
+
+.item-description {
+    font-size: 0.95rem;
+    font-weight: 500;
+}
+
+.item-notes {
+    width: 100%;
+    padding: 8px 12px;
+    border: 1px solid var(--border);
+    border-radius: 6px;
+    font-size: 0.85rem;
+    min-height: 36px;
+}
+
+.item-note-display {
+    font-size: 0.85rem;
+    color: var(--text-secondary);
+    font-style: italic;
+}
+
+.notes-textarea {
+    resize: vertical;
+    min-height: 100px;
+}
+
+/* Photos */
+.photo-btn {
+    margin-bottom: 12px;
+}
+
+.photo-grid {
+    display: grid;
+    grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
+    gap: 8px;
+    margin-top: 12px;
+}
+
+.photo-thumbnail {
+    position: relative;
+    aspect-ratio: 1;
+    border-radius: 8px;
+    overflow: hidden;
+}
+
+.photo-thumbnail.large {
+    aspect-ratio: 4/3;
+    grid-column: span 2;
+}
+
+.photo-thumbnail img {
+    width: 100%;
+    height: 100%;
+    object-fit: cover;
+}
+
+.photo-remove {
+    position: absolute;
+    top: 4px;
+    right: 4px;
+    width: 28px;
+    height: 28px;
+    border-radius: 50%;
+    background: var(--danger);
+    color: white;
+    border: none;
+    font-size: 0.9rem;
+    cursor: pointer;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+}
+
+.photo-time {
+    position: absolute;
+    bottom: 4px;
+    left: 4px;
+    background: rgba(0,0,0,0.6);
+    color: white;
+    font-size: 0.7rem;
+    padding: 2px 6px;
+    border-radius: 4px;
+}
+
+/* Sync badges */
+.sync-badge {
+    display: inline-block;
+    font-size: 0.7rem;
+    padding: 2px 8px;
+    border-radius: 12px;
+    font-weight: 600;
+    text-transform: uppercase;
+}
+
+.badge-pending {
+    background: var(--warning);
+    color: #333;
+}
+
+.badge-synced {
+    background: var(--success);
+    color: white;
+}
+
+.badge-failed {
+    background: var(--danger);
+    color: white;
+}
+
+/* Inspection cards */
+.inspection-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    margin-bottom: 8px;
+}
+
+.inspection-date {
+    font-weight: 600;
+    font-size: 0.9rem;
+}
+
+.inspection-summary {
+    margin: 0;
+    font-size: 0.9rem;
+    color: var(--text-secondary);
+}
+
+.inspection-notes {
+    margin: 4px 0 0;
+    font-size: 0.85rem;
+    color: var(--text-secondary);
+    white-space: nowrap;
+    overflow: hidden;
+    text-overflow: ellipsis;
+}
+
+.inspection-meta {
+    color: var(--text-secondary);
+    font-size: 0.9rem;
+    margin: 4px 0 0;
+}
+
+.inspection-summary-bar {
+    display: flex;
+    justify-content: space-around;
+    padding: 16px;
+    background: var(--card-bg);
+    border-radius: var(--radius);
+    box-shadow: var(--shadow);
+    margin-top: 16px;
+    font-weight: 600;
+    font-size: 0.9rem;
+}
+
+.general-notes {
+    background: var(--card-bg);
+    padding: 12px 16px;
+    border-radius: 8px;
+    border: 1px solid var(--border);
+}
+
+/* Sticky save button */
+.sticky-bottom {
+    position: sticky;
+    bottom: 70px;
+    background: var(--bg);
+    padding: 12px 0;
+    z-index: 50;
+}
+
+/* States */
+.loading {
+    text-align: center;
+    padding: 40px 16px;
+    color: var(--text-secondary);
+}
+
+.empty-state {
+    text-align: center;
+    padding: 40px 16px;
+    color: var(--text-secondary);
+}
+
+/* Error UI */
+#blazor-error-ui {
+    background: lightyellow;
+    bottom: 0;
+    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
+    display: none;
+    left: 0;
+    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
+    position: fixed;
+    width: 100%;
+    z-index: 1000;
+}
+
+#blazor-error-ui .dismiss {
+    cursor: pointer;
+    position: absolute;
+    right: 0.75rem;
+    top: 0.5rem;
+}
+

