using SiteInspector.Client.Pages;
using SiteInspector.Components;
using System.Collections.Concurrent;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveWebAssemblyComponents();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (app.Environment.IsDevelopment())
{
    app.UseWebAssemblyDebugging();
}
else
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
    // The default HSTS value is 30 days. You may want to change this for production scenarios, see https://aka.ms/aspnetcore-hsts.
    app.UseHsts();
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseHttpsRedirection();

app.UseAntiforgery();

app.MapStaticAssets();

// In-memory storage for synced data
var syncedInspections = new ConcurrentBag<object>();
var sites = new ConcurrentDictionary<string, object>();

// API Endpoints
app.MapGet("/api/sites", () => Results.Ok(sites.Values));

app.MapPost("/api/sites", (object site) =>
{
    var id = Guid.NewGuid().ToString();
    sites[id] = site;
    return Results.Created($"/api/sites/{id}", site);
});

app.MapPost("/api/sync/inspections", (object inspection) =>
{
    syncedInspections.Add(inspection);
    return Results.Ok(new { synced = true });
});

app.MapRazorComponents<App>()
    .AddInteractiveWebAssemblyRenderMode()
    .AddAdditionalAssemblies(typeof(SiteInspector.Client._Imports).Assembly);

app.Run();

